/**
 * Order Service Tests
 *
 * Unit tests for OrderService covering:
 * - Order CRUD operations
 * - Status workflow management
 * - Order item operations
 * - Event emission
 *
 * @module modules/order/__tests__/order.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { OrderService } from '@/modules/order/order.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { OrderRepository, PaginatedResult } from '@/modules/order/order.repository';
import type { TableRepository } from '@/modules/order/table.repository';
import type { EventService } from '@/core/services/event.service';
import type {
  Order,
  OrderWithRelations,
  OrderItem,
  OrderStatus,
  Table,
} from '@/modules/order/order.types';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock OrderRepository
 */
function createMockOrderRepository(): {
  findAll: Mock;
  findAllSummaries: Mock;
  findById: Mock;
  findByIdWithRelations: Mock;
  findByIdOrThrow: Mock;
  findByOrderNumber: Mock;
  findActiveOrders: Mock;
  findByStatus: Mock;
  orderNumberExists: Mock;
  count: Mock;
  getNextOrderNumber: Mock;
  create: Mock;
  update: Mock;
  updateStatus: Mock;
  recalculateTotals: Mock;
  getOrderItems: Mock;
  addOrderItem: Mock;
  updateOrderItem: Mock;
  updateOrderItemStatus: Mock;
  removeOrderItem: Mock;
  getOrderItem: Mock;
  getOrderItemOrThrow: Mock;
  getStatistics: Mock;
} {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findByOrderNumber: vi.fn(),
    findActiveOrders: vi.fn(),
    findByStatus: vi.fn(),
    orderNumberExists: vi.fn(),
    count: vi.fn(),
    getNextOrderNumber: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateStatus: vi.fn(),
    recalculateTotals: vi.fn(),
    getOrderItems: vi.fn(),
    addOrderItem: vi.fn(),
    updateOrderItem: vi.fn(),
    updateOrderItemStatus: vi.fn(),
    removeOrderItem: vi.fn(),
    getOrderItem: vi.fn(),
    getOrderItemOrThrow: vi.fn(),
    getStatistics: vi.fn(),
  };
}

/**
 * Creates a mock TableRepository
 */
function createMockTableRepository(): {
  findById: Mock;
  setCurrentOrder: Mock;
} {
  return {
    findById: vi.fn(),
    setCurrentOrder: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock order for testing
 */
function createMockOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order_123',
    organizationId: 'org_123',
    branchId: null,
    orderNumber: 'ORD-20260201-0001',
    tableId: null,
    customerId: null,
    staffId: null,
    status: 'PENDING' as OrderStatus,
    type: 'DINE_IN',
    subtotal: 100,
    taxAmount: 10,
    discountAmount: 0,
    totalAmount: 110,
    currency: 'TRY',
    notes: null,
    confirmedAt: null,
    preparedAt: null,
    deliveredAt: null,
    completedAt: null,
    cancelledAt: null,
    cancelReason: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock order with relations
 */
function createMockOrderWithRelations(
  overrides: Partial<OrderWithRelations> = {}
): OrderWithRelations {
  return {
    ...createMockOrder(),
    items: [],
    table: null,
    customer: null,
    feedback: null,
    ...overrides,
  };
}

/**
 * Creates a mock order item for testing
 */
function createMockOrderItem(overrides: Partial<OrderItem> = {}): OrderItem {
  return {
    id: 'item_123',
    orderId: 'order_123',
    productId: 'prod_123',
    variantId: null,
    productName: 'Test Product',
    variantName: null,
    quantity: 2,
    unitPrice: 50,
    totalPrice: 100,
    modifiers: [],
    notes: null,
    status: 'PENDING',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock table for testing
 */
function createMockTable(overrides: Partial<Table> = {}): Table {
  return {
    id: 'table_123',
    organizationId: 'org_123',
    branchId: null,
    zoneId: null,
    number: '1',
    capacity: 4,
    status: 'AVAILABLE',
    currentOrderId: null,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('OrderService', () => {
  let service: OrderService;
  let mockRepository: ReturnType<typeof createMockOrderRepository>;
  let mockTableRepository: ReturnType<typeof createMockTableRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_123';

  beforeEach(() => {
    mockRepository = createMockOrderRepository();
    mockTableRepository = createMockTableRepository();
    mockEventService = createMockEventService();

    service = new OrderService(
      mockRepository as unknown as OrderRepository,
      mockTableRepository as unknown as TableRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated orders', async () => {
      // Arrange
      const orders = [createMockOrder(), createMockOrder({ id: 'order_456' })];
      const paginatedResult: PaginatedResult<Order> = {
        data: orders,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      };
      mockRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      const result = await service.list(orgId, { page: 1, perPage: 20 });

      // Assert
      expect(result).toEqual(paginatedResult);
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ page: 1, perPage: 20 })
      );
    });

    it('should apply status filter when provided', async () => {
      // Arrange
      const paginatedResult: PaginatedResult<Order> = {
        data: [createMockOrder({ status: 'PENDING' })],
        meta: { page: 1, perPage: 20, total: 1, totalPages: 1 },
      };
      mockRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      await service.list(orgId, { status: 'PENDING' });

      // Assert
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ status: 'PENDING' })
      );
    });
  });

  describe('getById', () => {
    it('should return order when found', async () => {
      // Arrange
      const order = createMockOrder();
      mockRepository.findById.mockResolvedValue(order);

      // Act
      const result = await service.getById(orgId, 'order_123');

      // Assert
      expect(result).toEqual(order);
      expect(mockRepository.findById).toHaveBeenCalledWith('order_123', orgId);
    });

    it('should return null when order not found', async () => {
      // Arrange
      mockRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById(orgId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return order with relations when found', async () => {
      // Arrange
      const orderWithRelations = createMockOrderWithRelations();
      mockRepository.findByIdWithRelations.mockResolvedValue(orderWithRelations);

      // Act
      const result = await service.getByIdWithRelations(orgId, 'order_123');

      // Assert
      expect(result).toEqual(orderWithRelations);
    });

    it('should throw AppException when order not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.getByIdWithRelations(orgId, 'nonexistent')
      ).rejects.toThrow(AppException);
    });
  });

  describe('getByOrderNumber', () => {
    it('should return order when found by order number', async () => {
      // Arrange
      const order = createMockOrder();
      mockRepository.findByOrderNumber.mockResolvedValue(order);

      // Act
      const result = await service.getByOrderNumber(orgId, 'ORD-20260201-0001');

      // Assert
      expect(result).toEqual(order);
      expect(mockRepository.findByOrderNumber).toHaveBeenCalledWith(
        orgId,
        'ORD-20260201-0001'
      );
    });
  });

  describe('getActiveOrders', () => {
    it('should return active orders', async () => {
      // Arrange
      const orders = [
        createMockOrder({ status: 'PENDING' }),
        createMockOrder({ id: 'order_456', status: 'CONFIRMED' }),
      ];
      mockRepository.findActiveOrders.mockResolvedValue(orders);

      // Act
      const result = await service.getActiveOrders(orgId);

      // Assert
      expect(result).toEqual(orders);
      expect(mockRepository.findActiveOrders).toHaveBeenCalledWith(orgId, undefined);
    });

    it('should filter by table when provided', async () => {
      // Arrange
      mockRepository.findActiveOrders.mockResolvedValue([]);

      // Act
      await service.getActiveOrders(orgId, 'table_123');

      // Assert
      expect(mockRepository.findActiveOrders).toHaveBeenCalledWith(orgId, 'table_123');
    });
  });

  describe('getPendingOrders', () => {
    it('should return pending orders', async () => {
      // Arrange
      const orders = [createMockOrder({ status: 'PENDING' })];
      mockRepository.findByStatus.mockResolvedValue(orders);

      // Act
      const result = await service.getPendingOrders(orgId);

      // Assert
      expect(result).toEqual(orders);
      expect(mockRepository.findByStatus).toHaveBeenCalledWith(orgId, 'PENDING');
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      type: 'DINE_IN' as const,
      items: [
        {
          productId: 'prod_123',
          quantity: 2,
        },
      ],
    };

    it('should create an order successfully', async () => {
      // Arrange
      const createdOrder = createMockOrder();
      const orderWithRelations = createMockOrderWithRelations();
      mockRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0001');
      mockRepository.create.mockResolvedValue(createdOrder);
      mockRepository.findByIdWithRelations.mockResolvedValue(orderWithRelations);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, validCreateData);

      // Assert
      expect(result.order).toEqual(orderWithRelations);
      expect(result.message).toContain('successfully');
      expect(mockRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({
          orderNumber: 'ORD-20260201-0001',
          status: 'PENDING',
          type: 'DINE_IN',
        }),
        expect.any(Array)
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.created',
        expect.objectContaining({
          orderId: createdOrder.id,
          organizationId: orgId,
        })
      );
    });

    it('should validate table when tableId is provided', async () => {
      // Arrange
      const table = createMockTable();
      mockTableRepository.findById.mockResolvedValue(table);
      mockRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0001');
      mockRepository.create.mockResolvedValue(createMockOrder({ tableId: 'table_123' }));
      mockRepository.findByIdWithRelations.mockResolvedValue(createMockOrderWithRelations());
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, { ...validCreateData, tableId: 'table_123' });

      // Assert
      expect(mockTableRepository.findById).toHaveBeenCalledWith('table_123', orgId);
    });

    it('should throw error when table not found', async () => {
      // Arrange
      mockTableRepository.findById.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.create(orgId, { ...validCreateData, tableId: 'nonexistent' })
      ).rejects.toThrow(AppException);
    });

    it('should throw error when table is reserved', async () => {
      // Arrange
      const reservedTable = createMockTable({ status: 'RESERVED' });
      mockTableRepository.findById.mockResolvedValue(reservedTable);

      // Act & Assert
      await expect(
        service.create(orgId, { ...validCreateData, tableId: 'table_123' })
      ).rejects.toThrow(AppException);
    });

    it('should update table status for dine-in orders', async () => {
      // Arrange
      const table = createMockTable();
      const createdOrder = createMockOrder({ tableId: 'table_123' });
      mockTableRepository.findById.mockResolvedValue(table);
      mockRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0001');
      mockRepository.create.mockResolvedValue(createdOrder);
      mockRepository.findByIdWithRelations.mockResolvedValue(
        createMockOrderWithRelations({ tableId: 'table_123' })
      );
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, { ...validCreateData, tableId: 'table_123' });

      // Assert
      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_123',
        orgId,
        createdOrder.id
      );
    });

    it('should throw validation error for invalid input', async () => {
      // Arrange
      const invalidData = { items: [] };

      // Act & Assert
      await expect(service.create(orgId, invalidData as any)).rejects.toThrow(
        AppException
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      notes: 'Updated notes',
    };

    it('should update an order successfully', async () => {
      // Arrange
      const existingOrder = createMockOrder();
      const updatedOrder = createMockOrder({ notes: 'Updated notes' });
      mockRepository.findByIdOrThrow.mockResolvedValue(existingOrder);
      mockRepository.update.mockResolvedValue(updatedOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update(orgId, 'order_123', validUpdateData);

      // Assert
      expect(result.order).toEqual(updatedOrder);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.updated',
        expect.objectContaining({
          orderId: updatedOrder.id,
          organizationId: orgId,
        })
      );
    });

    it('should throw error when order not found', async () => {
      // Arrange
      mockRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Order', 'nonexistent')
      );

      // Act & Assert
      await expect(
        service.update(orgId, 'nonexistent', validUpdateData)
      ).rejects.toThrow(AppException);
    });

    it('should throw error when order is not modifiable', async () => {
      // Arrange
      const completedOrder = createMockOrder({ status: 'COMPLETED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(completedOrder);

      // Act & Assert
      await expect(
        service.update(orgId, 'order_123', validUpdateData)
      ).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Status Change Operations Tests
  // ---------------------------------------------------------------------------

  describe('changeStatus', () => {
    it('should change order status successfully', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.updateStatus.mockResolvedValue(confirmedOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changeStatus(
        orgId,
        'order_123',
        { status: 'CONFIRMED' }
      );

      // Assert
      expect(result.order.status).toBe('CONFIRMED');
      expect(result.previousStatus).toBe('PENDING');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.status_changed',
        expect.objectContaining({
          previousStatus: 'PENDING',
          newStatus: 'CONFIRMED',
        })
      );
    });

    it('should throw error for invalid status transition', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);

      // Act & Assert
      await expect(
        service.changeStatus(orgId, 'order_123', { status: 'COMPLETED' })
      ).rejects.toThrow(AppException);
    });

    it('should require reason when cancelling', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);

      // Act & Assert
      await expect(
        service.changeStatus(
          orgId,
          'order_123',
          { status: 'CANCELLED' },
          { role: 'manager' }
        )
      ).rejects.toThrow(AppException);
    });

    it('should allow cancellation with reason', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const cancelledOrder = createMockOrder({
        status: 'CANCELLED',
        cancelReason: 'Customer request',
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.updateStatus.mockResolvedValue(cancelledOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.changeStatus(
        orgId,
        'order_123',
        { status: 'CANCELLED', reason: 'Customer request' },
        { role: 'manager' }
      );

      // Assert
      expect(result.order.status).toBe('CANCELLED');
      expect(mockRepository.updateStatus).toHaveBeenCalledWith(
        'order_123',
        orgId,
        'CANCELLED',
        'Customer request'
      );
    });

    it('should clear table on order completion', async () => {
      // Arrange
      const readyOrder = createMockOrder({ status: 'DELIVERED', tableId: 'table_123' });
      const completedOrder = createMockOrder({
        status: 'COMPLETED',
        tableId: 'table_123',
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(readyOrder);
      mockRepository.updateStatus.mockResolvedValue(completedOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.changeStatus(orgId, 'order_123', { status: 'COMPLETED' });

      // Assert
      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_123',
        orgId,
        null
      );
    });
  });

  describe('confirm', () => {
    it('should confirm a pending order', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.updateStatus.mockResolvedValue(confirmedOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.confirm(orgId, 'order_123');

      // Assert
      expect(result.order.status).toBe('CONFIRMED');
    });
  });

  describe('startPreparing', () => {
    it('should start preparing a confirmed order', async () => {
      // Arrange
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      const preparingOrder = createMockOrder({ status: 'PREPARING' });
      mockRepository.findByIdOrThrow.mockResolvedValue(confirmedOrder);
      mockRepository.updateStatus.mockResolvedValue(preparingOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.startPreparing(orgId, 'order_123');

      // Assert
      expect(result.order.status).toBe('PREPARING');
    });
  });

  describe('cancel', () => {
    it('should cancel an order with reason', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const cancelledOrder = createMockOrder({ status: 'CANCELLED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.updateStatus.mockResolvedValue(cancelledOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.cancel(
        orgId,
        'order_123',
        'Customer changed mind',
        { role: 'manager' }
      );

      // Assert
      expect(result.order.status).toBe('CANCELLED');
      expect(result.message).toContain('cancelled');
    });
  });

  // ---------------------------------------------------------------------------
  // Order Item Operations Tests
  // ---------------------------------------------------------------------------

  describe('getOrderItems', () => {
    it('should return order items', async () => {
      // Arrange
      const items = [createMockOrderItem(), createMockOrderItem({ id: 'item_456' })];
      mockRepository.findByIdOrThrow.mockResolvedValue(createMockOrder());
      mockRepository.getOrderItems.mockResolvedValue(items);

      // Act
      const result = await service.getOrderItems(orgId, 'order_123');

      // Assert
      expect(result).toEqual(items);
    });
  });

  describe('addItem', () => {
    const validItemData = {
      productId: 'prod_123',
      quantity: 1,
    };

    it('should add item to pending order', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const newItem = createMockOrderItem();
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.addOrderItem.mockResolvedValue(newItem);
      mockRepository.recalculateTotals.mockResolvedValue(pendingOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.addItem(orgId, 'order_123', validItemData);

      // Assert
      expect(result.item).toEqual(newItem);
      expect(result.message).toContain('added');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.item_added',
        expect.any(Object)
      );
    });

    it('should throw error when order is not in addable status', async () => {
      // Arrange
      const preparingOrder = createMockOrder({ status: 'PREPARING' });
      mockRepository.findByIdOrThrow.mockResolvedValue(preparingOrder);

      // Act & Assert
      await expect(
        service.addItem(orgId, 'order_123', validItemData)
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateItem', () => {
    const validUpdateData = {
      quantity: 3,
      notes: 'Extra spicy',
    };

    it('should update order item', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const existingItem = createMockOrderItem();
      const updatedItem = createMockOrderItem({ quantity: 3, notes: 'Extra spicy' });
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.getOrderItemOrThrow.mockResolvedValue(existingItem);
      mockRepository.updateOrderItem.mockResolvedValue(updatedItem);
      mockRepository.recalculateTotals.mockResolvedValue(pendingOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateItem(
        orgId,
        'order_123',
        'item_123',
        validUpdateData
      );

      // Assert
      expect(result.item).toEqual(updatedItem);
    });

    it('should throw error when order is completed', async () => {
      // Arrange
      const completedOrder = createMockOrder({ status: 'COMPLETED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(completedOrder);

      // Act & Assert
      await expect(
        service.updateItem(orgId, 'order_123', 'item_123', validUpdateData)
      ).rejects.toThrow(AppException);
    });
  });

  describe('removeItem', () => {
    it('should remove item from pending order', async () => {
      // Arrange
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const existingItem = createMockOrderItem();
      mockRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockRepository.getOrderItemOrThrow.mockResolvedValue(existingItem);
      mockRepository.removeOrderItem.mockResolvedValue(undefined);
      mockRepository.recalculateTotals.mockResolvedValue(pendingOrder);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.removeItem(orgId, 'order_123', 'item_123');

      // Assert
      expect(mockRepository.removeOrderItem).toHaveBeenCalledWith('item_123');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.item_removed',
        expect.any(Object)
      );
    });

    it('should throw error when order is not pending', async () => {
      // Arrange
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      mockRepository.findByIdOrThrow.mockResolvedValue(confirmedOrder);

      // Act & Assert
      await expect(
        service.removeItem(orgId, 'order_123', 'item_123')
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateItemStatus', () => {
    it('should update item status', async () => {
      // Arrange
      const order = createMockOrder();
      const existingItem = createMockOrderItem();
      const updatedItem = createMockOrderItem({ status: 'PREPARING' });
      mockRepository.findByIdOrThrow.mockResolvedValue(order);
      mockRepository.getOrderItemOrThrow.mockResolvedValue(existingItem);
      mockRepository.updateOrderItemStatus.mockResolvedValue(updatedItem);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateItemStatus(
        orgId,
        'order_123',
        'item_123',
        'PREPARING'
      );

      // Assert
      expect(result.status).toBe('PREPARING');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'order.item_status_changed',
